 32	func InstanceSettings(configService shared.ConfigService, disabled func(shared.InstanceSettings) bool) echo.MiddlewareFunc {
 33		return func(next echo.HandlerFunc) echo.HandlerFunc {
 34			return func(ctx echo.Context) error {
 35	
 36				settings, err := configService.GetInstanceSettings(ctx.Request().Context())
 37				if err != nil {
 38					slog.Error("could not get instance settings", "err", err)
 39					// if we can't get the settings, we allow the request to avoid blocking access in case of database issues
 40					return next(ctx)
 41				}
 42				if disabled(settings) {
 43					return echo.NewHTTPError(403, "this endpoint is disabled by the instance configuration")
 44				}
 45				return next(ctx)
 46			}
 47		}
 48	}
