 50	func OrganizationAccessControlMiddleware(obj shared.Object, act shared.Action) echo.MiddlewareFunc {
 51		return func(next echo.HandlerFunc) echo.HandlerFunc {
 52			return func(ctx echo.Context) error {
 53				// get the rbac
 54				rbac := shared.GetRBAC(ctx)
 55				org := shared.GetOrg(ctx)
 56				// get the user
 57				user := shared.GetSession(ctx).GetUserID()
 58	
 59				allowed, err := rbac.IsAllowed(ctx.Request().Context(), user, obj, act)
 60				if err != nil {
 61					ctx.Response().WriteHeader(500)
 62					return echo.NewHTTPError(500, "could not determine if the user has access").WithInternal(err)
 63				}
 64	
 65				// check if the user has the required role
 66				if !allowed {
 67					if org.IsPublic && act == shared.ActionRead {
 68						shared.SetIsPublicRequest(ctx)
 69					} else {
 70						slog.Error("access denied in accessControlMiddleware", "user", user, "object", obj, "action", act)
 71						ctx.Response().WriteHeader(404)
 72						return echo.NewHTTPError(404, "could not find organization")
 73					}
 74				}
 75	
 76				return next(ctx)
 77			}
 78		}
 79	}
