 98	func AssetAccessControlFactory(assetRepository shared.AssetRepository) shared.RBACMiddleware {
 99		return func(obj shared.Object, act shared.Action) shared.MiddlewareFunc {
100			return func(next echo.HandlerFunc) echo.HandlerFunc {
101				return func(ctx shared.Context) error {
102					// get the rbac
103					rbac := shared.GetRBAC(ctx)
104					// get the user
105					user := shared.GetSession(ctx).GetUserID()
106					// get the project
107					project := shared.GetProject(ctx)
108					// get the asset slug
109					assetSlug, err := shared.GetAssetSlug(ctx)
110					if err != nil {
111						return echo.NewHTTPError(400, "invalid asset slug")
112					}
113					var asset models.Asset
114					// check if asset is already set in the context
115					if a, ok := ctx.Get("asset").(models.Asset); ok {
116						asset = a
117					} else {
118						// get the asset by slug and project
119						asset, err = assetRepository.ReadBySlug(ctx.Request().Context(), nil, project.ID, assetSlug)
120						if err != nil {
121							return echo.NewHTTPError(404, "could not find asset")
122						}
123					}
124	
125					allowed, err := rbac.IsAllowedInAsset(ctx.Request().Context(), &asset, user, obj, act)
126					if err != nil {
127						return echo.NewHTTPError(500, "could not determine if the user has access")
128					}
129					// check if the user has the required role
130					if !allowed {
131						if asset.IsPublic && act == shared.ActionRead {
132							// allow READ on all objects in the project - if access is public
133							shared.SetIsPublicRequest(ctx)
134						} else {
135							slog.Warn("access denied in AssetAccess", "user", user, "object", obj, "action", act, "assetSlug", assetSlug)
136							return echo.NewHTTPError(404, "could not find asset")
137						}
138					}
139					shared.SetAsset(ctx, asset)
140					return next(ctx)
141				}
142			}
143		}
144	}
