152		}
153	
154		licenseRiskID := ctx.Param("licenseRiskID")
155		if licenseRiskID != "" {
156			id, err := uuid.Parse(licenseRiskID)
157			if err != nil {
158				return uuid.Nil, "", fmt.Errorf("invalid license risk id: %w", err)
159			}
160			return id, dtos.VulnTypeLicenseRisk, nil
161		}
162		licenseRiskIDFromGet, ok := ctx.Get("licenseRiskID").(string)
163		if ok && licenseRiskIDFromGet != "" {
164			id, err := uuid.Parse(licenseRiskIDFromGet)
