262	func ShareMiddleware(orgRepository shared.OrganizationRepository, projectRepository shared.ProjectRepository, assetRepository shared.AssetRepository, assetVersionRepository shared.AssetVersionRepository, artifactRepository shared.ArtifactRepository) echo.MiddlewareFunc {
263		return func(next echo.HandlerFunc) echo.HandlerFunc {
264			return func(ctx shared.Context) error {
265				// get the assetID from the url
266				assetID, err := shared.GetURLDecodedParam(ctx, "assetID")
267				if err != nil {
268					slog.Error("could not get assetID from url", "err", err)
269					return echo.NewHTTPError(400, "invalid assetID")
270				}
271	
272				assetUUID, err := uuid.Parse(assetID)
273				if err != nil {
274					slog.Error("invalid assetID format", "assetID", assetID, "err", err)
275					return echo.NewHTTPError(400, "invalid assetID format")
276				}
277				// get the asset
278				asset, err := assetRepository.Read(ctx.Request().Context(), nil, assetUUID)
279				if err != nil {
280					slog.Error("could not find asset in ShareMiddleware", "assetID", assetID, "err", err)
281					return echo.NewHTTPError(404, "could not find asset")
282				}
283				// fetch org and project
284				project, err := projectRepository.Read(ctx.Request().Context(), nil, asset.ProjectID)
285				if err != nil {
286					slog.Error("could not find project in ShareMiddleware", "assetID", assetID, "projectID", asset.ProjectID, "err", err)
287					return echo.NewHTTPError(404, "could not find asset")
288				}
289				org, err := orgRepository.Read(ctx.Request().Context(), nil, project.OrganizationID)
290				if err != nil {
291					slog.Error("could not find organization in ShareMiddleware", "assetID", assetID, "organizationID", project.OrganizationID, "err", err)
292					return echo.NewHTTPError(404, "could not find asset")
293				}
294	
295				// check if sharing is enabled
296				if !asset.SharesInformation {
297					slog.Warn("access denied in ShareMiddleware - sharing not enabled", "assetID", assetID)
298					return echo.NewHTTPError(404, "could not find asset")
299				}
300	
301				// resolve asset version from path param
302				assetVersionSlug, err := shared.GetURLDecodedParam(ctx, "assetVersionSlug")
303				if err != nil {
304					slog.Error("could not get assetVersionSlug from url", "err", err)
305					return echo.NewHTTPError(400, "invalid assetVersionSlug")
306				}
307				assetVersion, err := assetVersionRepository.ReadBySlug(ctx.Request().Context(), nil, asset.ID, assetVersionSlug)
308				if err != nil {
309					slog.Error("could not find asset version in ShareMiddleware", "assetID", assetID, "assetVersionSlug", assetVersionSlug, "err", err)
310					return echo.NewHTTPError(404, "could not find asset version")
311				}
312	
313				// resolve artifact from path param
314				artifactName, err := shared.GetURLDecodedParam(ctx, "artifactName")
315				if err != nil {
316					slog.Error("could not get artifactName from url", "err", err)
317					return echo.NewHTTPError(400, "invalid artifactName")
318				}
319				artifact, err := artifactRepository.ReadArtifact(ctx.Request().Context(), nil, artifactName, assetVersion.Name, asset.ID)
320				if err != nil {
321					slog.Error("could not find artifact in ShareMiddleware", "assetID", assetID, "artifactName", artifactName, "err", err)
322					return echo.NewHTTPError(404, "could not find artifact")
323				}
324				shared.SetArtifact(ctx, artifact)
325	
326				shared.SetOrg(ctx, org)
327				shared.SetProject(ctx, project)
328				shared.SetAsset(ctx, asset)
329				shared.SetAssetVersion(ctx, assetVersion)
