func TestMiddlewareNeededScope(t *testing.T) {
	t.Run("it should allow access if user has all required scopes", func(t *testing.T) {
		// arrange
		e := echo.New()
		req := httptest.NewRequest(http.MethodGet, "/", nil)
		rec := httptest.NewRecorder()
		ctx := e.NewContext(req, rec)

		mockSession := accesscontrol.NewSession("user-id", []string{"scope1", "scope2", "scope3"})
		ctx.Set("session", mockSession)

		middleware := middlewares.NeededScope([]string{"scope1", "scope2"})

		handler := func(ctx echo.Context) error {
			return ctx.JSON(http.StatusOK, "success")
		}
		// act
		handleWithMiddleware := middleware(handler)

		err := handleWithMiddleware(ctx)

		// assert
		assert.NoError(t, err)
		assert.Equal(t, http.StatusOK, rec.Code)
	})

	t.Run("it should deny access if user does not have all required scopes", func(t *testing.T) {
		// arrange
		e := echo.New()
		req := httptest.NewRequest(http.MethodGet, "/", nil)
		rec := httptest.NewRecorder()
		ctx := e.NewContext(req, rec)

		mockSession := accesscontrol.NewSession("user-id", []string{"scope1"})
		ctx.Set("session", mockSession)

		middleware := middlewares.NeededScope([]string{"scope1", "scope2"})

		// act
		err := middleware(func(ctx echo.Context) error {
			return ctx.JSON(http.StatusOK, "success")
		})(ctx) // nolint:errcheck

		// assert
		assert.Error(t, err)

		// should be an echo.HTTPError
		httpErr, ok := err.(*echo.HTTPError)
		assert.True(t, ok)
		assert.Equal(t, http.StatusForbidden, httpErr.Code)
	})

	t.Run("it should deny access if user has no scopes", func(t *testing.T) {
		// arrange
		e := echo.New()
		req := httptest.NewRequest(http.MethodGet, "/", nil)
		rec := httptest.NewRecorder()
		ctx := e.NewContext(req, rec)

		mockSession := accesscontrol.NewSession("user-id", []string{})
		ctx.Set("session", mockSession)

		middleware := middlewares.NeededScope([]string{"scope1"})

		// act
		err := middleware(func(ctx echo.Context) error {
			return ctx.JSON(http.StatusOK, "success")
		})(ctx) // nolint:errcheck

		// assert
		assert.Error(t, err)

		// should be an echo.HTTPError
		httpErr, ok := err.(*echo.HTTPError)
		assert.True(t, ok)
		assert.Equal(t, http.StatusForbidden, httpErr.Code)
	})

	t.Run("it should allow access if no scopes are required", func(t *testing.T) {
		// arrange
		e := echo.New()
		req := httptest.NewRequest(http.MethodGet, "/", nil)
		rec := httptest.NewRecorder()
		ctx := e.NewContext(req, rec)

		mockSession := accesscontrol.NewSession("user-id", []string{"scope1"})
		ctx.Set("session", mockSession)

		middleware := middlewares.NeededScope([]string{})

		// act
		err := middleware(func(ctx echo.Context) error {
			return ctx.JSON(http.StatusOK, "success")
		})(ctx)

		// assert
		assert.NoError(t, err)
		assert.Equal(t, http.StatusOK, rec.Code)
	})
}

