type informationSource struct {
	URL  string  `json:"url"`
	Purl *string `json:"purl"`
	// type can be "csaf", "vex", "sbom"
	Type string `json:"type,omitempty"`
}

func informationSourceToString(source informationSource) string {
	r := source.URL
	if source.Purl != nil && *source.Purl != "" {
		r = *source.Purl + ":" + r
	}
	if source.Type != "" {
		r = source.Type + ":" + r
	}
	return r
}

